 .card-wrap {
 // push
 display: flex;
 flex-direction: column;
 align-items: flex-start;
 padding: 0.5em;
 flex: none;
 order: 1;
 flex-basis: 33%;

 .card {
 display: flex;
 flex-direction: column;
 align-items: stretch;

 img {
 // Rectangle 22
 border-radius: 2em 2em 2em 2em;
 order: 0;
 align-self: stretch;
 max-width: 90%;
 max-height: 10%;
 padding: 0.5em;
 }

 .content {
 // Frame 2
 display: flex;
 flex-direction: column;
 align-items: flex-start;
 padding: 0;
 gap: 0.5em;
 flex: none;
 order: 1;
 align-self: stretch;

// p.type {
