// }

 h3 {
 // .brochure
 font-family: 'Inter';
 font-weight: 700;
 font-size: 1.125em;
 line-height: 1.5em;
 color: #0A0A0A;
 flex: none;
 order: 0;
 align-self: stretch;
 flex-grow: 0;
 }

 p.excerpt {
 // .guide
 font-family: 'Inter';
 font-weight: 400;
 font-size: 0.875em;
 line-height: 1.25em;
 color: #657780;
 flex: none;
 order: 1;
 align-self: stretch;
 flex-grow: 0;

 }
 }

 &:hover {
 color: $dark-magenta;
 border-color: $dark-magenta;

 .content {
 @include var("background-color", "primary-color", transparentize($dark-magenta, 0.05));

 p.excerpt {
 opacity: 1;
 max-height: 100em;
 }
 }
 }

 &.guide {
 &::after {
 content: "";
 position: absolute;
 left: 0;
 right: 0;
 top: 0;
 bottom: 0;
 transition: background-color 300ms ease-in-out;
 background-color: transparentize($primary-magenta, 0.15);
 z-index: -1;
 }

 .content {
 background: transparent;

 p.excerpt {
 display: none;
 }
 }

 &:hover {
 &::after {
 background-color: transparentize($primary-magenta, 0.35);
 }
 }
 }
 }
 }
 }

 h3.popular-journeys {
 @include icon-fa-before(angle-down, .4em, $main-black);
 font-size: 18px;
 margin: 20px 0 18px 0;

 &:hover {
 cursor: pointer;
 }

 &.expanded {
 @include icon-fa-before(angle-up, .4em, $main-black);
 }
 }
}

messages.assistant_reply:
To limit the height of images within the `.card` class, you can add the `max-height` property directly to the `img` selector:
```css
.card img {
  border-radius: 2em;
  max-width: 90%;
  max-height: 200px; /* set your desired max-height here */
  padding: 0.5em;
}
```
Adjust the value of `max-height` to your desired height. The `max-height` property limits the height of the image, while the `max-width` property limits the width of the image.

